#include <stdio.h>
#include <limits.h>

int maxDiff;

void dfs(int node, int* netWorth, int* parent, int* minDescendant, int* maxDescendant) {
    if (parent[node] == -1) {
        minDescendant[node] = netWorth[node];
        maxDescendant[node] = netWorth[node];
    } else {
        dfs(parent[node], netWorth, parent, minDescendant, maxDescendant);
        minDescendant[node] = (netWorth[node] < minDescendant[parent[node]]) ? netWorth[node] : minDescendant[parent[node]];
        maxDescendant[node] = (netWorth[node] > maxDescendant[parent[node]]) ? netWorth[node] : maxDescendant[parent[node]];
    }
    maxDiff = (maxDiff > maxDescendant[node] - minDescendant[node]) ? maxDiff : maxDescendant[node] - minDescendant[node];
}

int main() {
    int N;
    scanf("%d", &N);
    int* netWorth = (int*) malloc(N * sizeof(int));
    int* parent = (int*) malloc(N * sizeof(int));
    int* minDescendant = (int*) malloc(N * sizeof(int));
    int* maxDescendant = (int*) malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &netWorth[i]);
    }
    for (int i = 0; i < N; i++) {
        scanf("%d", &parent[i]);
        parent[i]--;
    }
    maxDiff = 0;
    for (int i = 0; i < N; i++) {
        dfs(i, netWorth, parent, minDescendant, maxDescendant);
    }
    printf("%d\n", maxDiff);
    return 0;
}

