import java.util.Scanner;
public class Main {
    static int maxDiff;
    public static void dfs(int node, int[] netWorth, int[] parent, int[] minDescendant, int[] maxDescendant) {
        if (parent[node] == -1) {
            minDescendant[node] = netWorth[node];
            maxDescendant[node] = netWorth[node];
        } else {
            dfs(parent[node], netWorth, parent, minDescendant, maxDescendant);
            minDescendant[node] = (netWorth[node] < minDescendant[parent[node]]) ? netWorth[node] : minDescendant[parent[node]];
            maxDescendant[node] = (netWorth[node] > maxDescendant[parent[node]]) ? netWorth[node] : maxDescendant[parent[node]];
        }
        maxDiff = (maxDiff > maxDescendant[node] - minDescendant[node]) ? maxDiff : maxDescendant[node] - minDescendant[node];
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[] netWorth = new int[N];
        int[] parent = new int[N];
        int[] minDescendant = new int[N];
        int[] maxDescendant = new int[N];
        for (int i = 0; i < N; i++) {
            netWorth[i] = scanner.nextInt();
        }
        for (int i = 0; i < N; i++) {
            parent[i] = scanner.nextInt() - 1;
        }
        maxDiff = 0;
        for (int i = 0; i < N; i++) {
            dfs(i, netWorth, parent, minDescendant, maxDescendant);
        }
        System.out.println(maxDiff);
    }
}

